vulnerability.source_evidence:
// ScalarReplacement.cpp lines 287-304:
      case MDefinition::Opcode::Slots: {
#ifdef DEBUG
        // Assert that MSlots are only used by MStoreDynamicSlot and
        // MLoadDynamicSlot.
        MSlots* ins = def->toSlots();
        MOZ_ASSERT(ins->object() != 0);
        for (MUseIterator i(ins->usesBegin()); i != ins->usesEnd(); i++) {
          // toDefinition should normally never fail, since they don't get
          // captured by resume points.
          MDefinition* def = (*i)->consumer()->toDefinition();
          MOZ_ASSERT(
              def->op() == MDefinition::Opcode::StoreDynamicSlot ||
              def->op() == MDefinition::Opcode::LoadDynamicSlot ||
              def->op() == MDefinition::Opcode::StoreDynamicSlotFromOffset ||
              def->op() == MDefinition::Opcode::LoadDynamicSlotFromOffset);
        }
#endif
        break;  // In release: no validation at all, unconditional non-escape
      }

trigger.sequence:
1. Create a plain object with enough properties to require dynamic slots
2. Access the object's slots in a way that creates an MSlots node with an unexpected consumer
3. For example, pass the slots pointer through a Phi node or use it in a TypedArray-like access pattern
4. In release builds, the missing assertion allows the object to be scalar-replaced despite the slots escaping
5. Example:
   function trigger() {
     let obj = {a:1, b:2, c:3, d:4, e:5, f:6, g:7, h:8, i:9, j:10, k:11, l:12, m:13};
     let arr = [obj.a, obj.b, obj.c, obj.d, obj.e, obj.f, obj.g, obj.h, obj.i, obj.j, obj.k, obj.l, obj.m];
     return arr;
   }
   for (let i = 0; i < 200000; i++) trigger();
